const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json || {};
return [{ json: Object.assign({}, r, { data: data }) }];

// Generate a bold background image per signage slide with the shared image provider
// (gpt-image-2). Images are written to a temp work dir on disk and only file paths
// are set on each slide — never base64 — so n8n execution data stays tiny. Graceful:
// slides whose image fails fall back to the branded gradient.
const fs = require('fs');
const H = this.helpers;
const r = $json || {};
const d = r.data || {};
const topic = r.topic || 'Security Awareness';
const A = function (x) { return Array.isArray(x) ? x : (x == null || x === '' ? [] : [x]); };
const want = Number(r.slides) || 5;
const slides = A(d.slides).slice(0, want);
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
const enabled = (($env.SIGNAGE_IMAGES || $env.CYBER_SECTION_IMAGES || 'true').toString().toLowerCase() !== 'false');
const baseu = ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1');
const model = ($env.IMAGE_MODEL || 'gpt-image-1');
const QV = { low:1, medium:1, high:1, auto:1 };
let quality = String($env.SIGNAGE_IMAGE_QUALITY || $env.COMIC_IMAGE_QUALITY || 'medium').toLowerCase(); if (!QV[quality]) quality = 'medium';
let conc = parseInt($env.IMAGE_CONCURRENCY || '3', 10); if (!(conc > 0)) conc = 3; if (conc > 8) conc = 8;
let timeout = parseInt($env.IMAGE_TIMEOUT || '120000', 10); if (!(timeout > 0)) timeout = 120000;

const baseName = (r.fileSafe || 'signage') + '-' + (r.date || new Date().toISOString().slice(0, 10));
const workDir = '/reports/awareness/signage/.work/' + baseName;
try { fs.mkdirSync(workDir, { recursive: true }); } catch (e) {}

const STYLE = 'Bold, premium digital-signage background illustration, cinematic and high-contrast, modern and clean, teal and deep-navy colour palette, dramatic lighting, subtle abstract cyber-security motifs (shield, padlock, network). Strong empty/negative space on the LEFT half for a large headline overlay. ';
const NEG = ' No text, no words, no letters, no logos, no watermark, no charts, no UI, no borders.';

async function mapLimit(items, limit, fn) {
  const ret = new Array(items.length); let idx = 0;
  async function worker() { while (idx < items.length) { const cur = idx++; ret[cur] = await fn(items[cur], cur); } }
  const n = Math.max(1, Math.min(limit, items.length));
  const workers = []; for (let w = 0; w < n; w++) workers.push(worker());
  await Promise.all(workers);
  return ret;
}
async function gen(prompt) {
  const resp = await H.httpRequest({ method: 'POST', url: baseu + '/images/generations',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
    body: { model: model, prompt: prompt, size: '1536x1024', quality: quality, n: 1 }, json: true, timeout: timeout });
  return resp && resp.data && resp.data[0] && resp.data[0].b64_json;
}

let ok = 0, failed = 0;
if (enabled && key && slides.length) {
  const res = await mapLimit(slides, conc, async function (s, k) {
    let file = '';
    const subj = (s.headline || topic) + (s.sub ? ('. ' + s.sub) : '');
    try {
      const b64 = await gen(STYLE + 'Theme: ' + subj + '.' + NEG);
      if (b64) { file = workDir + '/slide-' + String(k + 1).padStart(2, '0') + '.png'; fs.writeFileSync(file, Buffer.from(b64, 'base64')); ok++; }
      else failed++;
    } catch (e) { failed++; }
    return { k: k, file: file };
  });
  res.forEach(function (x) { if (x.file && slides[x.k]) slides[x.k].bg = x.file; });
}

return [{ json: Object.assign({}, r, { data: d, workDir: workDir, imagesGenerated: ok, imagesFailed: failed }) }];

// Render each digital-signage slide as a 1920x1080 HTML page: a full-bleed
// gpt-image-2 background (read from disk, embedded only at render time) under a
// legibility gradient, with a bold left-aligned headline block, accent rule, pills,
// and a Jarvis brand mark. Falls back to a branded gradient when no image. Gotenberg
// screenshots each one to a PNG. Emits one item per slide.
const _fs = (function(){ try { return require('fs'); } catch (e) { return null; } })();
const r = $json || {};
const d = r.data || {};
const topic = r.topic || 'Security Awareness';
const client = (r.client || '').toString();
const brand = client ? client : 'Security Awareness';
const want = Number(r.slides) || 5;
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function arr(x){ return Array.isArray(x)?x:(x==null||x===''?[]:[x]); }
function imgSrc(p){ if(!p) return ''; var s=String(p); if(s.indexOf('data:')===0) return s; if(_fs){ try{ return 'data:image/png;base64,'+_fs.readFileSync(s).toString('base64'); }catch(e){} } return ''; }
let slides = arr(d.slides).slice(0, want);
if(!slides.length){ for(var k=0;k<want;k++) slides.push({ headline:topic, sub:'Stay alert. Stay secure.', points:[] }); }
// Accent pairs (image overlay tint / gradient fallback): [deep, accent]
const palettes = [['#0A1A2F','#0E7C86'],['#0A1A2F','#1F8A4C'],['#0A1A2F','#2D6CB5'],['#0A1A2F','#B8860B'],['#0A1A2F','#7A3FB0']];
const SHIELD = '<svg viewBox="0 0 24 24" fill="none" stroke="#9fe4d8" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3l7 3v5c0 4.5-3 7.6-7 9-4-1.4-7-4.5-7-9V6z"/><path d="M9 12l2 2 4-4"/></svg>';

function slideHtml(s, idx){
  var pal = palettes[idx % palettes.length];
  var bg = imgSrc(s.bg);
  var pts = arr(s.points).slice(0,3);
  var ptsHtml = pts.length ? ('<div class="pts">'+pts.map(function(p){return '<span class="pt">'+esc(p)+'</span>';}).join('')+'</div>') : '';
  var CSS = "@page{size:1920px 1080px;margin:0} *{box-sizing:border-box} html,body{margin:0;padding:0} "
    +".slide{width:1920px;height:1080px;position:relative;overflow:hidden;font-family:-apple-system,'Segoe UI',Arial,sans-serif;color:#fff;background:"+pal[0]+"} "
    +".bg{position:absolute;inset:0;background-size:cover;background-position:center;z-index:0} "
    // legibility overlay — dark on the left where the headline sits, accent on the right
    +".ov{position:absolute;inset:0;z-index:1;background:linear-gradient(105deg,rgba(8,16,26,.95) 0%,rgba(8,16,26,.86) 34%,rgba(10,26,47,.5) 66%,"+pal[1]+"3d 100%)} "
    +".ovg{position:absolute;inset:0;z-index:0;background:linear-gradient(125deg,"+pal[0]+","+pal[1]+")} "
    +".edge{position:absolute;left:0;top:0;bottom:0;width:14px;background:"+pal[1]+";z-index:2} "
    +".mark{position:absolute;top:84px;right:110px;z-index:3;display:flex;align-items:center;gap:18px} .mark svg{width:60px;height:60px} .mark .mt{font-size:26px;letter-spacing:3px;text-transform:uppercase;color:#9fe4d8;font-weight:800} "
    +".inner{position:absolute;z-index:3;left:130px;right:130px;top:0;bottom:0;display:flex;flex-direction:column;justify-content:center} "
    +".kick{font-size:32px;letter-spacing:9px;text-transform:uppercase;color:#E7C76A;font-weight:800;margin-bottom:14px} "
    +".rule{width:130px;height:8px;background:"+pal[1]+";border-radius:4px;margin-bottom:30px} "
    +"h1{font-size:132px;line-height:1.0;margin:0;font-weight:800;max-width:1300px;letter-spacing:-1px;text-shadow:0 6px 30px rgba(0,0,0,.45)} "
    +".sub{font-size:50px;margin-top:34px;color:#eaf4f5;max-width:1180px;line-height:1.22;font-weight:500} "
    +".pts{display:flex;gap:22px;margin-top:54px;flex-wrap:wrap;max-width:1300px} .pt{background:rgba(255,255,255,.12);border:2px solid rgba(159,228,216,.5);border-radius:50px;padding:18px 40px;font-size:36px;font-weight:700;color:#fff} "
    +".foot{position:absolute;z-index:3;left:130px;bottom:78px;font-size:30px;color:#cfe0e6;font-weight:700;letter-spacing:1px} "
    +".pg{position:absolute;z-index:3;right:130px;bottom:78px;font-size:30px;color:#9fb6c2} "
    +".accent{position:absolute;left:0;right:0;bottom:0;height:12px;z-index:2;background:linear-gradient(90deg,#E7C76A,"+pal[1]+")}";
  return '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body><div class="slide">'
    + (bg ? ('<div class="bg" style="background-image:url('+bg+')"></div><div class="ov"></div>') : '<div class="ovg"></div>')
    + '<div class="edge"></div>'
    + '<div class="mark">'+SHIELD+'<span class="mt">'+esc(brand)+'</span></div>'
    + '<div class="inner"><div class="kick">'+esc(topic)+'</div><div class="rule"></div>'
    +   '<h1>'+esc(s.headline||topic)+'</h1>'
    +   (s.sub?('<div class="sub">'+esc(s.sub)+'</div>'):'')
    +   ptsHtml
    + '</div>'
    + '<div class="foot">'+esc(brand)+' &middot; Security Awareness</div><div class="pg">'+(idx+1)+' / '+slides.length+'</div>'
    + '<div class="accent"></div>'
    + '</div></body></html>';
}

const out = slides.map(function(s, idx){
  var html = slideHtml(s, idx);
  return { json: { idx:idx, total:slides.length, topic:topic, date:r.date, fileSafe:r.fileSafe },
    binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType:'text/html', fileName:'index.html' } } };
});
// Backgrounds are now baked into each slide's HTML — clean the temp work dir.
if (r.workDir && r.workDir.indexOf('/.work/') >= 0 && _fs) { try { _fs.rmSync(r.workDir, { recursive: true, force: true }); } catch (e) {} }
return out;

const fs = require('fs');
const meta = $('Render Slides').first().json || {};
const dir = '/reports/awareness/signage';
const base = 'signage-' + (meta.fileSafe || 'set') + '-' + (meta.date || new Date().toISOString().slice(0,10));
function _crcT(){ var c,t=[]; for(var n=0;n<256;n++){ c=n; for(var k=0;k<8;k++) c=(c&1)?(0xEDB88320^(c>>>1)):(c>>>1); t[n]=c>>>0; } return t; }
var CT=_crcT();
function crc32(b){ var c=0xFFFFFFFF; for(var i=0;i<b.length;i++) c=CT[(c^b[i])&0xFF]^(c>>>8); return (c^0xFFFFFFFF)>>>0; }
function zipStore(entries){ var dt=new Date(); var T=((dt.getHours()&31)<<11)|((dt.getMinutes()&63)<<5)|((Math.floor(dt.getSeconds()/2))&31); var D=(((dt.getFullYear()-1980)&127)<<9)|(((dt.getMonth()+1)&15)<<5)|(dt.getDate()&31); var local=[],central=[],off=0; entries.forEach(function(e){ var name=Buffer.from(e.name,'utf8'); var data=Buffer.isBuffer(e.data)?e.data:Buffer.from(String(e.data),'utf8'); var crc=crc32(data); var lh=Buffer.alloc(30); lh.writeUInt32LE(0x04034b50,0);lh.writeUInt16LE(20,4);lh.writeUInt16LE(0,6);lh.writeUInt16LE(0,8);lh.writeUInt16LE(T,10);lh.writeUInt16LE(D,12);lh.writeUInt32LE(crc,14);lh.writeUInt32LE(data.length,18);lh.writeUInt32LE(data.length,22);lh.writeUInt16LE(name.length,26);lh.writeUInt16LE(0,28); local.push(lh,name,data); var ch=Buffer.alloc(46); ch.writeUInt32LE(0x02014b50,0);ch.writeUInt16LE(20,4);ch.writeUInt16LE(20,6);ch.writeUInt16LE(0,8);ch.writeUInt16LE(0,10);ch.writeUInt16LE(T,12);ch.writeUInt16LE(D,14);ch.writeUInt32LE(crc,16);ch.writeUInt32LE(data.length,20);ch.writeUInt32LE(data.length,24);ch.writeUInt16LE(name.length,28);ch.writeUInt16LE(0,30);ch.writeUInt16LE(0,32);ch.writeUInt16LE(0,34);ch.writeUInt16LE(0,36);ch.writeUInt32LE(0,38);ch.writeUInt32LE(off,42); central.push(ch,name); off+=30+name.length+data.length; }); var cd=Buffer.concat(central), body=Buffer.concat(local); var eo=Buffer.alloc(22); eo.writeUInt32LE(0x06054b50,0);eo.writeUInt16LE(0,4);eo.writeUInt16LE(0,6);eo.writeUInt16LE(entries.length,8);eo.writeUInt16LE(entries.length,10);eo.writeUInt32LE(cd.length,12);eo.writeUInt32LE(body.length,16);eo.writeUInt16LE(0,20); return Buffer.concat([body,cd,eo]); }
const items = $input.all();
const entries = [];
for (let i = 0; i < items.length; i++) {
  let buf = null;
  try { buf = await this.helpers.getBinaryDataBuffer(i, 'data'); } catch (e) {}
  if (buf && buf.length) entries.push({ name: 'slide-' + String(i+1).padStart(2,'0') + '.png', data: buf });
}
let primary = null, name = base + '.zip';
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
if (entries.length) { primary = zipStore(entries); try { fs.writeFileSync(dir + '/' + name, primary); } catch (e) {} }
const out = { json: { ok: !!primary, file: dir + '/' + name, slides: entries.length, topic: meta.topic } };
if (primary) { const bin = await this.helpers.prepareBinaryData(primary, name, 'application/zip'); out.binary = { data: bin }; }
return [out];
